import React, { useState } from 'react';
import './Css/Login.css'; // Your new folder structure!

const Login = ({ toggleSlide }) => {
  const [data, setData] = useState({ username: '', password: '' });

  const handleLogin = async (e) => {
    e.preventDefault();
    const response = await fetch('http://localhost:8000/login', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    });
    const result = await response.json();
    alert(result.message);
  };

  return (
    <div className="login-content">
      <h1>Hi Gamer</h1>
      <p className="subtitle">Welcome to the Gaming Hub</p>

      <form onSubmit={handleLogin}>
        <input type="text" placeholder="Username" required onChange={(e) => setData({...data, username: e.target.value})} />
        <input type="password" placeholder="Password" required onChange={(e) => setData({...data, password: e.target.value})} />

        <div className="forgot-password">Forgot password?</div>

        <div className="divider">
          <span>or</span>
        </div>

        <button type="button" className="google-btn">
          <img src="https://upload.wikimedia.org/wikipedia/commons/c/c1/Google_%22G%22_logo.svg" alt="Google" />
          Login with Google
        </button>

        <button type="submit" className="main-btn">Login</button>
      </form>

      <div className="login-switch">
        Don't have an account? <span onClick={toggleSlide}>Sign up</span>
      </div>

      {/* Placeholder for your bottom social icons */}
      <div className="social-icons">
        <div className="icon-circle">f</div>
        <div className="icon-circle">t</div>
        <div className="icon-circle">in</div>
      </div>
    </div>
  );
};

export default Login;
